const raw  = $input.first().json;
const body = (raw.body !== undefined) ? raw.body : raw;

if (!body.job_id)  throw new Error('Missing job_id from Stage 1');
if (!body.scenes || !Array.isArray(body.scenes) || body.scenes.length === 0)
  throw new Error('Missing scenes[] from Stage 1');
if (!body.narration) throw new Error('Missing narration from Stage 1');

const MAX_CLIPS = 6;
const scenes = body.scenes.slice(0, MAX_CLIPS).map((s, i) => ({
  ...s,
  scene_number: i + 1,
  start_sec: i * 5,
  end_sec:   (i + 1) * 5,
  seedance_prompt: (s.seedance_prompt || '')
    .replace(/\b10 seconds\b/gi, '5 seconds')
    .replace(/\b10s\b/gi, '5s')
}));

const wsKey = $env.WAVESPEED_API_KEY || '';
if (!wsKey) console.warn('WARNING: WAVESPEED_API_KEY not set — Seedance calls will fail');

console.log('Stage 2 start | job:', body.job_id, '| scenes:', scenes.length, '| topic:', body.topic);

return [{ json: {
  ...body,
  scenes,
  num_clips:    scenes.length,
  clip_dur_sec: 5,
  ws_key:       wsKey
}}];

const fs            = require('fs');
const { execSync }  = require('child_process');

const jobData = $('Extract & Prepare').first().json;
const jobId   = jobData.job_id;
const narration = (jobData.narration || '').substring(0, 3000);
const n8nIn   = '/data/ffmpeg/input';

if (!fs.existsSync(n8nIn)) fs.mkdirSync(n8nIn, { recursive: true });

// Write narration to file — avoids all escaping problems
const narrationFile = n8nIn + '/' + jobId + '_narration.txt';
fs.writeFileSync(narrationFile, narration, 'utf8');

// Write Python script to shared volume
const scriptPath  = n8nIn + '/' + jobId + '_tts.py';
const containerBase = '/ffmpeg/input/' + jobId;

const pythonScript = `import asyncio, edge_tts, json

async def main():
    with open('${containerBase}_narration.txt', 'r', encoding='utf-8') as f:
        narration = f.read()
    job_id = '${jobId}'

    comm = edge_tts.Communicate(narration, voice='en-US-EmmaNeural', rate='-5%', pitch='+2Hz')
    audio_bytes = b''
    sentences = []

    async for chunk in comm.stream():
        if chunk['type'] == 'audio':
            audio_bytes += chunk['data']
        elif chunk['type'] == 'SentenceBoundary':
            sentences.append({
                'text': chunk['text'],
                'start': chunk['offset'] / 10000000,
                'end': (chunk['offset'] + chunk['duration']) / 10000000
            })

    audio_path = '/ffmpeg/input/' + job_id + '_voice.mp3'
    with open(audio_path, 'wb') as f:
        f.write(audio_bytes)

    word_timings = []
    if sentences:
        for sent in sentences:
            sent_words = sent['text'].strip().split()
            if not sent_words:
                continue
            duration = sent['end'] - sent['start']
            total_chars = sum(len(w) for w in sent_words)
            cursor = sent['start']
            for w in sent_words:
                word_dur = (len(w) / max(total_chars, 1)) * duration
                word_timings.append({
                    'word': w.rstrip('.,!?;:'),
                    'start': round(cursor, 3),
                    'end': round(cursor + word_dur, 3)
                })
                cursor += word_dur
    else:
        cursor = 0.1
        for w in narration.strip().split():
            dur = 0.38 * (0.8 + len(w) * 0.04)
            word_timings.append({'word': w, 'start': round(cursor, 3), 'end': round(cursor + dur, 3)})
            cursor += dur

    audio_duration = sentences[-1]['end'] + 0.5 if sentences else (word_timings[-1]['end'] + 0.5 if word_timings else 30)

    result = {'audio_path': audio_path, 'audio_duration': round(audio_duration, 3), 'word_timings': word_timings}
    with open('/ffmpeg/input/' + job_id + '_timings.json', 'w') as f:
        json.dump(result, f)
    print('Words:', len(word_timings), '| Duration:', round(audio_duration, 2), 's | Voice: en-US-AnaNeural')

asyncio.run(main())
`;

fs.writeFileSync(scriptPath, pythonScript);
console.log('Running edge-tts for job:', jobId);

const containerScript = '/ffmpeg/input/' + jobId + '_tts.py';
const out = execSync('docker exec qpc_ffmpeg_runner python3 "' + containerScript + '"', { timeout: 90000 }).toString();
console.log('edge-tts:', out.trim());

const timingsPath = n8nIn + '/' + jobId + '_timings.json';
const result = JSON.parse(fs.readFileSync(timingsPath, 'utf8'));

return [{ json: result }];

const jobData   = $('Extract & Prepare').first().json;
const ttsResult = $input.first().json;

if (!ttsResult.audio_path) throw new Error('edge-tts did not produce audio_path');
if (!ttsResult.word_timings || ttsResult.word_timings.length === 0) throw new Error('edge-tts produced no word timings');

console.log('Voice ready | words:', ttsResult.word_timings.length, '| duration:', ttsResult.audio_duration + 's');

return [{ json: {
  ...jobData,
  audio_path:     ttsResult.audio_path,
  audio_duration: ttsResult.audio_duration,
  word_timings:   ttsResult.word_timings
}}];

const https = require('https');
const data   = $input.first().json;
const scenes = data.scenes || [];
const wsKey  = data.ws_key || $env.WAVESPEED_API_KEY;

if (!wsKey) throw new Error('WAVESPEED_API_KEY not set. Add it in n8n → Settings → Environment Variables.');

function apiPost(body) {
  return new Promise((resolve, reject) => {
    const buf = Buffer.from(JSON.stringify(body));
    const req = https.request({
      hostname: 'api.wavespeed.ai',
      path: '/api/v3/bytedance/seedance-v1-lite-t2v-720p',
      method: 'POST',
      headers: { 'Authorization': 'Bearer ' + wsKey, 'Content-Type': 'application/json', 'Content-Length': buf.length }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => { try { resolve(JSON.parse(Buffer.concat(chunks).toString())); } catch(e) { reject(new Error('Bad JSON from Wavespeed')); } });
    });
    req.on('error', reject);
    req.write(buf);
    req.end();
  });
}

const promises = scenes.map((scene) => {
  const prompt = (scene.seedance_prompt || '')
    .replace(/\b10 seconds\b/gi, '5 seconds')
    .replace(/\b10s\b/gi, '5s');
  return apiPost({ prompt, duration: 5, aspect_ratio: '1:1', seed: -1 });
});

const results = await Promise.all(promises);
const seedance_job_ids = [];

for (let i = 0; i < results.length; i++) {
  const r = results[i];
  if (!r.data || !r.data.id) throw new Error('Scene ' + (i+1) + ' submit failed: ' + JSON.stringify(r).slice(0, 200));
  seedance_job_ids.push(r.data.id);
  console.log('[' + (i+1) + '/' + scenes.length + '] submitted → ' + r.data.id);
}

console.log('All ' + seedance_job_ids.length + ' scenes submitted. Waiting for generation...');
return [{ json: { ...data, seedance_job_ids, video_urls: new Array(scenes.length).fill(null), poll_attempt: 0, all_done: 0, submitted_at: Date.now() } }];

const https = require('https');
const data    = $input.first().json;
const wsKey   = data.ws_key || $env.WAVESPEED_API_KEY;
const jobIds  = data.seedance_job_ids || [];
const video_urls = [...(data.video_urls || [])];
const attempt = (data.poll_attempt || 0) + 1;

if (!wsKey) throw new Error('WAVESPEED_API_KEY not set.');

console.log('━━━ Poll attempt #' + attempt + ' (' + jobIds.length + ' clips) ━━━');

function apiGet(taskId) {
  return new Promise((resolve, reject) => {
    const req = https.request({
      hostname: 'api.wavespeed.ai',
      path: '/api/v3/predictions/' + taskId + '/result',
      method: 'GET',
      headers: { 'Authorization': 'Bearer ' + wsKey }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => { try { resolve(JSON.parse(Buffer.concat(chunks).toString())); } catch(e) { reject(new Error('Non-JSON from Wavespeed')); } });
    });
    req.on('error', reject);
    req.end();
  });
}

for (let i = 0; i < jobIds.length; i++) {
  if (video_urls[i] !== null) { console.log('Scene ' + (i+1) + ' already done, skipping'); continue; }
  const r = await apiGet(jobIds[i]);
  const status = (r.data && r.data.status) || 'unknown';
  const pct    = r.data && r.data.progress != null ? ' (' + r.data.progress + '%)' : '';
  console.log('Scene ' + (i+1) + '/' + jobIds.length + ' → ' + status + pct);
  if (status === 'completed') {
    const url = r.data.outputs && r.data.outputs[0];
    if (!url) throw new Error('Scene ' + (i+1) + ' completed but output URL missing');
    video_urls[i] = url;
    console.log('  ✓ ' + url.split('?')[0]);
  } else if (status === 'failed') {
    throw new Error('Scene ' + (i+1) + ' FAILED: ' + JSON.stringify(r.data));
  }
}

const done  = video_urls.filter(u => u !== null).length;
const total = jobIds.length;
const all_done = done === total ? 1 : 0;
console.log('Progress: ' + done + '/' + total + ' clips ready' + (all_done ? ' — ALL DONE!' : ' — next poll in 20s...'));

return [{ json: { ...data, video_urls, poll_attempt: attempt, all_done } }];

const { execSync } = require('child_process');
const fs      = require('fs');
const data    = $input.first().json;
const jobId   = data.job_id;
const urls    = data.video_urls || [];
const n8nIn   = '/data/ffmpeg/input';
const contIn  = '/ffmpeg/input';

if (!fs.existsSync(n8nIn)) fs.mkdirSync(n8nIn, { recursive: true });

const clipPaths = [];

for (let i = 0; i < urls.length; i++) {
  const url       = urls[i];
  const fileName  = jobId + '_scene' + (i + 1) + '.mp4';
  const n8nPath   = n8nIn  + '/' + fileName;
  const contPath  = contIn + '/' + fileName;

  // Download via docker container's curl
  const dlCmd = 'docker exec qpc_ffmpeg_runner curl -sL -o "' + contPath + '" "' + url + '" && echo DL_OK';
  const result = execSync(dlCmd, { encoding: 'utf-8', timeout: 120000 });

  if (!result.includes('DL_OK'))
    throw new Error('Download failed for scene ' + (i+1) + ': ' + url);

  if (!fs.existsSync(n8nPath))
    throw new Error('File not on disk after download: ' + n8nPath);

  clipPaths.push(n8nPath);
  console.log('Clip ' + (i+1) + ' saved: ' + fileName);
}

return [{ json: { ...data, clip_paths: clipPaths } }];

const fs           = require('fs');
const data         = $input.first().json;
const jobId        = data.job_id;
const wordTimings  = data.word_timings || [];
const hlKeywords   = (data.highlight_keywords || []).map(w => w.toLowerCase().replace(/[^a-z0-9]/g, ''));
const n8nIn        = '/data/ffmpeg/input';

function toASS(sec) {
  if (sec === null || sec === undefined || isNaN(sec)) sec = 0;
  const h  = Math.floor(sec / 3600);
  const m  = Math.floor((sec % 3600) / 60);
  const s  = Math.floor(sec % 60);
  const cs = Math.round((sec % 1) * 100);
  return h + ':' + String(m).padStart(2,'0') + ':' + String(s).padStart(2,'0') + '.' + String(cs).padStart(2,'0');
}

// Active word: yellow + scale pop 120%→100% over 200ms
const ACTIVE_ON  = '{\\c&H00FFFF&\\fscx120\\fscy120\\t(0,200,\\fscx100\\fscy100)}';
const ACTIVE_OFF = '{\\c&HFFFFFF&\\fscx100\\fscy100}';
const INACTIVE   = '{\\c&HFFFFFF&}';

const CHUNK = 3;
const dialogueLines = [];

for (let i = 0; i < wordTimings.length; i += CHUNK) {
  const chunk = wordTimings.slice(i, i + CHUNK);
  if (chunk.length === 0) break;

  // Original casing — no toUpperCase
  const chunkWords = chunk.map(w => w.word);

  for (let j = 0; j < chunk.length; j++) {
    const wStart = chunk[j].start;
    const wEnd   = chunk[j].end;
    if (wStart === null || wEnd === null) continue;

    const isHl = hlKeywords.some(kw => chunkWords[j].toLowerCase().replace(/[^a-z0-9]/g, '') === kw);

    const parts = chunkWords.map((w, k) => {
      const active = (k === j) || isHl;
      return active ? (ACTIVE_ON + w + ACTIVE_OFF) : (INACTIVE + w);
    });

    // Slide-up motion: each word group pops up 25px over 150ms
    const motion = '{\\move(540,1460,540,1430,0,150)}';

    dialogueLines.push(
      'Dialogue: 0,' + toASS(wStart) + ',' + toASS(wEnd) + ',Caption,,0,0,0,,' + motion + parts.join(' ')
    );
  }
}

const assContent = [
  '[Script Info]',
  'Title: Seedance High Nice Captions',
  'ScriptType: v4.00+',
  'WrapStyle: 2',
  'PlayResX: 1080',
  'PlayResY: 1920',
  '',
  '[V4+ Styles]',
  'Format: Name, Fontname, Fontsize, PrimaryColour, SecondaryColour, OutlineColour, BackColour, Bold, Italic, Underline, StrikeOut, ScaleX, ScaleY, Spacing, Angle, BorderStyle, Outline, Shadow, Alignment, MarginL, MarginR, MarginV, Encoding',
  'Style: Caption,Arial,52,&H00FFFFFF,&H000000FF,&H00000000,&H80000000,-1,0,0,0,100,100,0,0,1,3,0,2,30,30,60,1',
  '',
  '[Events]',
  'Format: Layer, Start, End, Style, Name, MarginL, MarginR, MarginV, Effect, Text',
  ...dialogueLines
].join('\n');

const assPath = n8nIn + '/' + jobId + '_captions.ass';
fs.writeFileSync(assPath, assContent, 'utf8');
console.log('ASS captions: ' + dialogueLines.length + ' lines | motion+pop enabled → ' + assPath);

return [{ json: { ...data, ass_path: assPath } }];

const data = $input.first().json;
return [{ json: {
  // identity
  job_id:             data.job_id,
  topic:              data.topic,
  category:           data.category,
  title:              data.title,
  hashtags:           data.hashtags,
  narration:          data.narration,
  opening_line:       data.opening_line,
  cta:                data.cta,
  // clips
  clip_paths:         data.clip_paths,
  num_clips:          data.num_clips,
  clip_dur_sec:       data.clip_dur_sec,
  // audio
  audio_path:         data.audio_path,
  audio_duration:     data.audio_duration,
  word_timings:       data.word_timings,
  // captions
  ass_path:           data.ass_path,
  highlight_keywords: data.highlight_keywords,
  // metadata
  sheet_row:          data.sheet_row,
  start_time:         data.start_time,
  subject:            data.subject || '',
  energy_vein_location: data.energy_vein_location || ''
}}];
